class Solution:
    def canIWin(self, maxChoosableInteger: int, desiredTotal: int) -> bool:
        if (maxChoosableInteger * (maxChoosableInteger + 1)) // 2 < desiredTotal:
            return False
        self.memo = {}
        return self.dfs((1 << (maxChoosableInteger + 1)) - 2, desiredTotal, maxChoosableInteger)

    def dfs(self, mask, total, maxChoosableInteger):
        if mask in self.memo:
            return self.memo[mask]
        for i in range(maxChoosableInteger, 0, -1):
            if (mask >> i) & 1:
                if i >= total or not self.dfs(mask ^ (1 << i), total - i, maxChoosableInteger):
                    self.memo[mask] = True
                    return True
        self.memo[mask] = False
        return False
